COPY public.query_history (id, question, generated_sql, created_at, sql_query) FROM stdin;
3	jugadores de los 6 mejores equipos de inglaterra con más goles marcados en la temporada 24-25	\N	2026-05-19 20:25:37.967026	SELECT\n    ps.name,\n    ps.team_name,\n    ps.goals\nFROM\n    player_stats ps\nWHERE\n    ps.season = '2425' AND ps.competition = 'Premier League' AND ps.team_name IN (\n        SELECT\n            s.team_name\n        FROM\n            standings s\n        WHERE\n            s.competition = 'Premier League' AND s.season = '2425'\n        ORDER BY\n            s.points DESC\n        LIMIT 6\n    )\nORDER BY\n    ps.goals DESC\nLIMIT 100
4	delanteros con más penaltis marcados en la liga española y francesa entre las temporadas 20-21 y 21-22	\N	2026-05-20 18:50:01.21917	SELECT name, SUM(penalties_scored) AS total_penaltis_marcados\nFROM player_stats\nWHERE pos IN ('FW', 'ST', 'CF')\nAND competition IN ('La Liga', 'Ligue 1')\nAND season IN ('2021', '2122')\nGROUP BY name\nORDER BY total_penaltis_marcados DESC\nLIMIT 100
5	delanteros con más penaltis marcados en la liga española y francesa entre las temporadas 20-21 y 21-22	\N	2026-05-20 18:51:48.966569	SELECT name, SUM(penalties_scored) AS total_penaltis_marcados\nFROM player_stats\nWHERE pos = 'FW'\nAND competition IN ('La Liga', 'Ligue 1')\nAND season IN ('2021', '2122')\nGROUP BY name\nORDER BY total_penaltis_marcados DESC\nLIMIT 100
6	delanteros con más penaltis marcados en la liga española y francesa entre las temporadas 20-21 y 21-22	\N	2026-05-20 18:54:01.338885	SELECT name, team_name, SUM(penalties_scored) AS total_penaltis_marcados\nFROM player_stats\nWHERE pos IN ('FW', 'F', 'AMF') AND competition IN ('La Liga', 'Ligue 1') AND season IN ('2021', '2122')\nGROUP BY name, team_name\nORDER BY total_penaltis_marcados DESC\nLIMIT 100
7	jugadores con peor contribuciones de gol sin penalti siendo delanteros o centrocampistas teniendo la mayor cantidad de minutos en la liga española temporada 23-24	\N	2026-05-20 19:15:21.775239	SELECT name, non_penalty_goal_contributions FROM player_stats WHERE pos LIKE '%FW%' OR pos LIKE '%MF%' AND competition IN ('La Liga') AND season IN (2324) ORDER BY minutes DESC, non_penalty_goal_contributions ASC LIMIT 100
8	porteros con alguna contribución de gol en todas las temporadas disponibles de la base de datos en cualquier de las ligas guardadas en la base de datos	\N	2026-05-20 19:17:24.536531	SELECT name, SUM(goal_contributions) AS total_contribuciones_gol\nFROM player_stats\nWHERE pos LIKE '%GK%' AND goal_contributions > 0\nGROUP BY name\nLIMIT 100
9	porteros con alguna contribución de gol en todas las temporadas disponibles de la base de datos en cualquier de las ligas guardadas en la base de datos	\N	2026-05-25 19:33:52.200657	SELECT\n  name\nFROM\n  player_stats\nWHERE\n  pos LIKE '%GK%' AND goal_contributions > 0\nGROUP BY\n  name\nHAVING\n  COUNT(DISTINCT season || competition) = (SELECT COUNT(DISTINCT season || competition) FROM player_stats)\nLIMIT 100
10	porteros con alguna contribución de gol en todas las temporadas disponibles de la base de datos en cualquier de las ligas guardadas en la base de datos	\N	2026-05-25 19:36:33.040743	SELECT DISTINCT name, season, competition\nFROM player_stats\nWHERE pos LIKE '%GK%' AND goal_contributions > 0\nORDER BY name, season, competition\nLIMIT 100
11	porteros con alguna contribución de gol en todas las temporadas disponibles de la base de datos en cualquier de las ligas guardadas en la base de datos	\N	2026-05-25 19:39:54.380331	SELECT name, team_name, season, competition, goal_contributions\nFROM player_stats\nWHERE pos LIKE '%GK%' AND goal_contributions > 0\nORDER BY goal_contributions DESC\nLIMIT 100
12	jugadores con peor contribuciones de gol sin penalti siendo delanteros o centrocampistas teniendo la mayor cantidad de minutos en la liga española temporada 23-24	\N	2026-05-25 19:59:18.02628	SELECT name, team_name, competition, season, non_penalty_goal_contributions, minutes\nFROM player_stats\nWHERE (pos LIKE '%FW%' OR pos LIKE '%MF%')\n  AND competition = 'La Liga'\n  AND season = 2324\nORDER BY non_penalty_goal_contributions ASC, minutes DESC\nLIMIT 100
13	Defensas con más goles en la liga española en las temporadas disponibles	\N	2026-05-25 22:25:23.646803	SELECT name, season, competition, goals FROM player_stats WHERE pos LIKE '%DF%' AND competition = 'La Liga' ORDER BY goals DESC LIMIT 100
